75	/*! \brief The config for disaggregation requests. */
76	class DisaggConfig {
77	 public:
78	  DisaggRequestKind kind = DisaggRequestKind::kNone;
79	  std::vector<Shape> kv_append_metadata;
80	  // "kv_window_begin" and "kv_window_end" denote the KV interval of interests.
81	  // "kv_window_end" supports Python style negative indexing.
82	  // The concrete meaning varies for different special request kind:
83	  // - For "prepare_receive", the begin is always 0, and "[0:end]" denotes
84	  // the KV range to prefill on a prefill instance.
85	  // - For "remote_send", "[begin:end]" means the KV range to compute prefill
86	  // and send to the decode instance.
87	  // - For "start_generation", the end is always nullopt, and "[begin:]" denotes
88	  // the KV range to prefill locally on the decode instance.
89	  std::optional<int> kv_window_begin = std::nullopt;
90	  std::optional<int> kv_window_end = std::nullopt;
91	  std::optional<int> dst_group_offset = std::nullopt;
92	
93	  static Result<DisaggConfig> FromJSON(const tvm::ffi::json::Object& config_json);
94	  tvm::ffi::json::Object AsJSON() const;
95	};
