175	/****************** Engine config ******************/
176	
177	/*!
178	 * \brief The engine mode in MLC LLM.
179	 * We provide three preset modes: "local", "interactive" and "server".
180	 * The default mode is "local".
181	 * The choice of mode decides the values of "max_batch_size", "max_total_sequence_length"
182	 * and "prefill_chunk_size" when they are not explicitly specified.
183	 * 1. Mode "local" refers to the local server deployment which has low
184	 * request concurrency. So the max batch size will be set to 4, and max
185	 * total sequence length and prefill chunk size are set to the context
186	 * window size (or sliding window size) of the model.
187	 * 2. Mode "interactive" refers to the interactive use of server, which
188	 * has at most 1 concurrent request. So the max batch size will be set to 1,
189	 * and max total sequence length and prefill chunk size are set to the context
190	 * window size (or sliding window size) of the model.
191	 * 3. Mode "server" refers to the large server use case which may handle
192	 * many concurrent request and want to use GPU memory as much as possible.
193	 * In this mode, we will automatically infer the largest possible max batch
194	 * size and max total sequence length.
195	 */
196	enum class EngineMode : int {
197	  kLocal = 0,
198	  kInteractive = 1,
199	  kServer = 2,
200	};
201	
202	/*! \brief The prefix cache mode. */
203	enum class PrefixCacheMode : int {
204	  /*! \brief Disable prefix cache. */
205	  kDisable = 0,
206	  /*! \brief The paged radix tree based prefix cache mode. */
207	  kRadix = 1,
208	};
209	
210	/*! \brief The speculative mode. */
211	enum class SpeculativeMode : int {
212	  /*! \brief Disable speculative decoding. */
213	  kDisable = 0,
214	  /*! \brief The normal speculative decoding (small draft) mode. */
215	  kSmallDraft = 1,
216	  /*! \brief The eagle-style speculative decoding. */
217	  kEagle = 2,
218	  /*! \brief The Medusa-style speculative decoding. */
219	  kMedusa = 3,
220	};
221	
222	/*! \brief The prefill mode. */
